mapper.select:
SELECT template_id, company_id, title, content, created_by, created_at
FROM approval_template
WHERE template_id = #{templateId}

mapper.update:
UPDATE approval_template
SET title = #{title}, content = #{content}
WHERE template_id = #{templateId}
  AND company_id = #{companyId}

mapper.delete:
DELETE FROM approval_template
WHERE template_id = #{templateId}
  AND company_id = #{companyId}

mapper.update:
UPDATE approval_doc
SET is_deleted = 1
WHERE doc_id = #{docId}
  AND writer_id = #{writerId}
  AND status = '대기'
